import{_ as e,o as s,c as r,Q as a}from"./chunks/framework.1b6086f5.js";const P=JSON.parse('{"title":"readinessProbe[就绪探针]","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Pods/readinessProbe.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Pods/readinessProbe.md","lastUpdated":1704383113000}'),t={name:"doc/DevOps/Kubernetes/基础/Pods/readinessProbe.md"},o=a('<h1 id="readinessprobe-就绪探针" tabindex="-1">readinessProbe[就绪探针] <a class="header-anchor" href="#readinessprobe-就绪探针" aria-label="Permalink to &quot;readinessProbe[就绪探针]&quot;">​</a></h1><p>就绪探针用于检测容器是否已经准备好接收流量。</p><p>对于就绪探针（Readiness Probe）：如果就绪探针失败，Kubernetes 将从服务负载均衡的池中剔除该容器。这意味着新的流量将不会被路由到该容器，直到就绪探针成功为止。</p><p>这可以确保只有健康的容器能够接收流量，避免将流量发送到尚未准备好的容器上。一旦就绪探针成功，Kubernetes 将再次将容器纳入服务负载均衡，并开始将新的流量路由到该容器。</p><p>初始延迟之前的就绪状态默认为Failure。如果容器不提供就绪探针，则默认状态为Success。</p><ul><li><strong>影响Pod的READY状态</strong></li><li><strong>影响 kubectl get endpoints 显示结果信息</strong></li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><ul><li><a href="./livenessProbe">参考</a></li></ul>',8),n=[o];function i(d,c,l,p,_,b){return s(),r("div",null,n)}const h=e(t,[["render",i]]);export{P as __pageData,h as default};
